// Gamboa: crawl del listado maestro /coches-ocasion-madrid?pagina=N (24/pág, server-rendered).
// ~463 coches = ~20 páginas. Ponemos 22 con margen; las de más devuelven vacío (skip).
const MAX_PAGES = 22;
const out = [];
for (let p = 1; p <= MAX_PAGES; p++) {
  out.push({ json: { url: 'https://www.gamboaocasion.com/coches-ocasion-madrid?pagina=' + p } });
}
return out;

// Gamboa – transform: HTML de listado (?pagina=N) → tarjetas → UPSERT en moveadvisor_marketplace_vo_offers
const httpOut = $input.item.json;
const html = typeof httpOut === 'string' ? httpOut : String(httpOut.data || httpOut.body || '');
const BASE = 'https://www.gamboaocasion.com';

function esc(v) {
  if (v === null || v === undefined) return 'NULL';
  if (typeof v === 'number') return isNaN(v) ? 'NULL' : String(v);
  return "'" + String(v).replace(/'/g, "''") + "'";
}
function normFuel(s) {
  s = String(s || '').toLowerCase();
  if (s.indexOf('eléctric') !== -1 || s.indexOf('electric') !== -1) return 'Eléctrico';
  const ench = s.indexOf('enchufable') !== -1 && s.indexOf('no enchufable') === -1;
  if (s.indexOf('híbrido') !== -1 || s.indexOf('hibrido') !== -1) return ench ? 'Híbrido enchufable' : 'Híbrido';
  if (s.indexOf('diésel') !== -1 || s.indexOf('diesel') !== -1) return 'Diesel';
  if (s.indexOf('gasolina') !== -1) return 'Gasolina';
  if (s.indexOf('glp') !== -1 || s.indexOf('gnc') !== -1 || s.indexOf('gas ') !== -1) return 'Gas';
  return '';
}
function normGear(s) {
  s = String(s || '').toLowerCase();
  if (s.indexOf('autom') !== -1) return 'Automatica';
  if (s.indexOf('manual') !== -1) return 'Manual';
  return '';
}

// localizar cada tarjeta por su <a title="Coche ..." href="...-ID">
const anchorRe = /<a title="Coche ([^"]*?)"\s+href="(\/[a-z0-9-]+-ocasion-madrid\/[a-z0-9-]+-(\d+))"/gi;
const anchors = [];
let m;
while ((m = anchorRe.exec(html)) !== null) anchors.push({ name: m[1].trim(), href: m[2], id: m[3], index: m.index });

const seen = {};
const rows = [];
for (let i = 0; i < anchors.length; i++) {
  const a = anchors[i];
  if (seen[a.id]) continue;
  seen[a.id] = 1;
  const block = html.slice(a.index, anchors[i + 1] ? anchors[i + 1].index : a.index + 2600);

  const ctitle = (block.match(/<h3 class="card-title">([^<]*)<\/h3>/i) || [])[1] || '';
  const brandModel = ctitle.replace(/\s+/g, ' ').trim();
  const sp = brandModel.indexOf(' ');
  const brand = sp === -1 ? brandModel : brandModel.slice(0, sp);
  const model = sp === -1 ? '' : brandModel.slice(sp + 1);
  const version = ((block.match(/<p class="card-text">([^<]*)<\/p>/i) || [])[1] || '').replace(/\s+/g, ' ').trim();
  const title = (a.name || (brandModel + ' ' + version)).replace(/\s+/g, ' ').trim();

  const img = (block.match(/src="(\/img\/coches\/\d+\/[^"]+)"/i) || [])[1] || '';
  const imageUrl = img ? (BASE + img) : '';

  const priceM = block.match(/€\s*(\d{1,3}(?:\.\d{3})+)/);
  const price = priceM ? priceM[1].replace(/\./g, '') : null;

  const text = block.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ');
  const powerM = text.match(/(\d{2,4})\s*cv/i);
  const power = powerM ? (powerM[1] + ' CV') : null;
  const yearM = text.match(/\b(20\d{2}|19\d{2})\b/);
  const year = yearM ? yearM[1] : null;
  const kmM = text.match(/(\d{1,3}(?:\.\d{3})*)\s*km/i);
  const mileage = kmM ? kmM[1].replace(/\./g, '') : null;
  const fuel = normFuel(text);
  const transmission = normGear(text);

  if (!price) continue; // sin precio no insertamos (obligatorio)

  const id = 'gamboa_' + a.id;
  const row = '(' +
    esc(id) + ', ' + esc(title) + ', ' + esc(brand) + ', ' + esc(model) + ', ' + esc(version) + ', ' +
    price + ', ' + (year || 'NULL') + ', ' + (mileage || 'NULL') + ', ' +
    esc(fuel) + ', ' + esc(power) + ', ' + esc(transmission) + ', ' +
    esc(imageUrl) + ', ' + esc(BASE + a.href) + ', ' +
    "'usado', 'concesionario', 'gamboa', 'Gamboa Ocasión', 'Madrid', 'Madrid', true, true, NOW(), NOW()" +
  ')';
  rows.push(row);
}

if (!rows.length) return [{ json: { sql: null, count: 0 } }];

const cols = 'id, title, brand, model, version, price, year, mileage, fuel, power, transmission, ' +
  'image_url, source_url, vehicle_condition, seller_type, portal, seller, location, provincia, ' +
  'available_for_purchase, is_active, created_at, updated_at';

const onConflict = 'ON CONFLICT (id) DO UPDATE SET ' +
  'title = EXCLUDED.title, price = EXCLUDED.price, mileage = EXCLUDED.mileage, ' +
  'year = COALESCE(EXCLUDED.year, moveadvisor_marketplace_vo_offers.year), ' +
  'version = EXCLUDED.version, fuel = EXCLUDED.fuel, power = EXCLUDED.power, ' +
  'transmission = EXCLUDED.transmission, ' +
  "image_url = COALESCE(NULLIF(moveadvisor_marketplace_vo_offers.image_url,''), EXCLUDED.image_url), " +
  'source_url = EXCLUDED.source_url, is_active = TRUE, updated_at = NOW()';

const sql = 'INSERT INTO moveadvisor_marketplace_vo_offers (' + cols + ') VALUES ' + rows.join(', ') + ' ' + onConflict;
return [{ json: { sql: sql, count: rows.length } }];
